(self.webpackChunkcheatsheet=self.webpackChunkcheatsheet||[]).push([[9092],{1061:(n,a,s)=>{"use strict";s.r(a),s.d(a,{data:()=>e});const e={key:"v-0ad65b7e",path:"/python/module/math/",title:"โมดูล Math",lang:"en-US",frontmatter:{},excerpt:"",headers:[{level:2,title:"ฟังก์ชั่นที่ควรรู้ไว้",slug:"ฟังก์ชั่นที่ควรรู้ไว้",children:[{level:3,title:"Absolute Values",slug:"absolute-values",children:[]},{level:3,title:"Exponent",slug:"exponent",children:[]},{level:3,title:"Root of n",slug:"root-of-n",children:[]},{level:3,title:"Logarithms",slug:"logarithms",children:[]},{level:3,title:"Rounding Up",slug:"rounding-up",children:[]},{level:3,title:"Rounding Down",slug:"rounding-down",children:[]},{level:3,title:"Factorial",slug:"factorial",children:[]},{level:3,title:"Calculate GCD",slug:"calculate-gcd",children:[]},{level:3,title:"Pi Constant",slug:"pi-constant",children:[]},{level:3,title:"Trigonometric Functions",slug:"trigonometric-functions",children:[]},{level:3,title:"เปลี่ยน Degrees -> Radians",slug:"เปลี่ยน-degrees-radians",children:[]}]}],filePathRelative:"python/module/math/README.md",git:{updatedTime:162676698e4,contributors:[]}}},7617:(n,a,s)=>{"use strict";s.r(a),s.d(a,{default:()=>t});const e=(0,s(6252).uE)('<h1 id="โมดูล-math" tabindex="-1"><a class="header-anchor" href="#โมดูล-math" aria-hidden="true">#</a> โมดูล Math</h1><p>หลังจากน้องๆได้ลองเล่น function แบบ built-in กันไปแล้ว<br></p><p>สำหรับน้องๆที่ยังไม่เข้าใจว่า built-in function คืออะไร ก็ให้ไปเรียน concept ของมันซะก่อนนะครับ</p><p>แต่ใน lecture นี้ พี่มงก็จะทำการอธิบายเกี่ยวกับ module <code>math</code> นั่นเอง</p><h2 id="ฟังก์ชั่นที่ควรรู้ไว้" tabindex="-1"><a class="header-anchor" href="#ฟังก์ชั่นที่ควรรู้ไว้" aria-hidden="true">#</a> ฟังก์ชั่นที่ควรรู้ไว้</h2><p>เนื่องจากมันมีเยอะมากๆๆๆๆๆ พี่มงก็เลยเลือกอันที่ต้องใช้บ่อยๆมาแล้วกันครับ อันอื่นๆ น้องอาจจะเข้าไปดูได้ในเว็บไซต์ของ Python.org ครับ</p><h3 id="absolute-values" tabindex="-1"><a class="header-anchor" href="#absolute-values" aria-hidden="true">#</a> Absolute Values</h3><p>Make the integer or float becomes positive only.</p><div class="language-python ext-py line-numbers-mode"><pre class="language-python"><code>math<span class="token punctuation">.</span>fabs<span class="token punctuation">(</span><span class="token punctuation">[</span>value<span class="token punctuation">]</span><span class="token punctuation">)</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br></div></div><p>or use built-in function <code>abs()</code> instead.</p><h3 id="exponent" tabindex="-1"><a class="header-anchor" href="#exponent" aria-hidden="true">#</a> Exponent</h3><p>or use exponent ** sign Returns value as x**y</p><div class="language-python ext-py line-numbers-mode"><pre class="language-python"><code>math<span class="token punctuation">.</span><span class="token builtin">pow</span><span class="token punctuation">(</span><span class="token punctuation">[</span>value<span class="token punctuation">]</span><span class="token punctuation">,</span> <span class="token punctuation">[</span>exponent power<span class="token punctuation">]</span><span class="token punctuation">)</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br></div></div><h3 id="root-of-n" tabindex="-1"><a class="header-anchor" href="#root-of-n" aria-hidden="true">#</a> Root of n</h3><p>Returns value as x^1/2 (square root)</p><div class="language-python ext-py line-numbers-mode"><pre class="language-python"><code>math<span class="token punctuation">.</span>sqrt<span class="token punctuation">(</span><span class="token punctuation">[</span><span class="token builtin">float</span> <span class="token keyword">or</span> integer<span class="token punctuation">]</span><span class="token punctuation">)</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br></div></div><h3 id="logarithms" tabindex="-1"><a class="header-anchor" href="#logarithms" aria-hidden="true">#</a> Logarithms</h3><p>Returns the value as log [base] [number]</p><div class="language-python ext-py line-numbers-mode"><pre class="language-python"><code>math<span class="token punctuation">.</span>log<span class="token punctuation">(</span><span class="token punctuation">[</span>number<span class="token punctuation">]</span><span class="token punctuation">,</span> <span class="token punctuation">[</span>base<span class="token punctuation">]</span><span class="token punctuation">)</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br></div></div><p>or use a predefined log level</p><div class="language-python ext-py line-numbers-mode"><pre class="language-python"><code>math<span class="token punctuation">.</span>log2<span class="token punctuation">(</span><span class="token punctuation">[</span>number<span class="token punctuation">]</span><span class="token punctuation">)</span>\nmath<span class="token punctuation">.</span>log10<span class="token punctuation">(</span><span class="token punctuation">[</span>number<span class="token punctuation">]</span><span class="token punctuation">)</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><h3 id="rounding-up" tabindex="-1"><a class="header-anchor" href="#rounding-up" aria-hidden="true">#</a> Rounding Up</h3><p>Returns value as integer (rounding up)</p><div class="language-python ext-py line-numbers-mode"><pre class="language-python"><code>math<span class="token punctuation">.</span>ceil<span class="token punctuation">(</span><span class="token punctuation">[</span><span class="token builtin">float</span> <span class="token keyword">or</span> integer<span class="token punctuation">]</span><span class="token punctuation">)</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br></div></div><h3 id="rounding-down" tabindex="-1"><a class="header-anchor" href="#rounding-down" aria-hidden="true">#</a> Rounding Down</h3><p>Returns value as integer (rounding down)</p><div class="language-python ext-py line-numbers-mode"><pre class="language-python"><code>math<span class="token punctuation">.</span>floor<span class="token punctuation">(</span><span class="token punctuation">[</span><span class="token builtin">float</span> <span class="token keyword">or</span> integer<span class="token punctuation">]</span><span class="token punctuation">)</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br></div></div><h3 id="factorial" tabindex="-1"><a class="header-anchor" href="#factorial" aria-hidden="true">#</a> Factorial</h3><p>Returns the value of the value factorial</p><div class="language-python ext-py line-numbers-mode"><pre class="language-python"><code>math<span class="token punctuation">.</span>factorial<span class="token punctuation">(</span><span class="token punctuation">[</span>integer<span class="token punctuation">]</span><span class="token punctuation">)</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br></div></div><h3 id="calculate-gcd" tabindex="-1"><a class="header-anchor" href="#calculate-gcd" aria-hidden="true">#</a> Calculate GCD</h3><p>Returns the GCD of integer A and B</p><div class="language-python ext-py line-numbers-mode"><pre class="language-python"><code>math<span class="token punctuation">.</span>gcd<span class="token punctuation">(</span><span class="token punctuation">[</span>integer_a<span class="token punctuation">]</span><span class="token punctuation">,</span> <span class="token punctuation">[</span>integer_a<span class="token punctuation">]</span><span class="token punctuation">)</span>\n\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><h3 id="pi-constant" tabindex="-1"><a class="header-anchor" href="#pi-constant" aria-hidden="true">#</a> Pi Constant</h3><p>Returns the value of pi (more accurate than 22/7, but not for 355/113)</p><div class="language-python ext-py line-numbers-mode"><pre class="language-python"><code>math<span class="token punctuation">.</span>pi<span class="token punctuation">(</span><span class="token punctuation">)</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br></div></div><h3 id="trigonometric-functions" tabindex="-1"><a class="header-anchor" href="#trigonometric-functions" aria-hidden="true">#</a> Trigonometric Functions</h3><div class="language-python ext-py line-numbers-mode"><pre class="language-python"><code>math<span class="token punctuation">.</span>sin<span class="token punctuation">(</span><span class="token operator">&lt;</span>radians<span class="token operator">&gt;</span><span class="token punctuation">)</span>\nmath<span class="token punctuation">.</span>cos<span class="token punctuation">(</span><span class="token operator">&lt;</span>radians<span class="token operator">&gt;</span><span class="token punctuation">)</span>\nmath<span class="token punctuation">.</span>tan<span class="token punctuation">(</span><span class="token operator">&lt;</span>radians<span class="token operator">&gt;</span><span class="token punctuation">)</span>\n\nmath<span class="token punctuation">.</span>csc<span class="token punctuation">(</span><span class="token operator">&lt;</span>radians<span class="token operator">&gt;</span><span class="token punctuation">)</span>\nmath<span class="token punctuation">.</span>sec<span class="token punctuation">(</span><span class="token operator">&lt;</span>radians<span class="token operator">&gt;</span><span class="token punctuation">)</span>\nmath<span class="token punctuation">.</span>cot<span class="token punctuation">(</span><span class="token operator">&lt;</span>radians<span class="token operator">&gt;</span><span class="token punctuation">)</span>\n\nmath<span class="token punctuation">.</span>arcsin<span class="token punctuation">(</span><span class="token operator">&lt;</span>radians<span class="token operator">&gt;</span><span class="token punctuation">)</span>\nmath<span class="token punctuation">.</span>arccos<span class="token punctuation">(</span><span class="token operator">&lt;</span>radians<span class="token operator">&gt;</span><span class="token punctuation">)</span>\nmath<span class="token punctuation">.</span>arctan<span class="token punctuation">(</span><span class="token operator">&lt;</span>radians<span class="token operator">&gt;</span><span class="token punctuation">)</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br></div></div><p>มันใช้หน่วยที่เป็น input คือ <code>radians</code> ไม่ใช่หน่วย <code>degrees</code> นะครับ</p><h3 id="เปลี่ยน-degrees-radians" tabindex="-1"><a class="header-anchor" href="#เปลี่ยน-degrees-radians" aria-hidden="true">#</a> เปลี่ยน Degrees -&gt; Radians</h3><div class="language-python ext-py line-numbers-mode"><pre class="language-python"><code>math<span class="token punctuation">.</span>radians<span class="token punctuation">(</span><span class="token punctuation">[</span>degree<span class="token punctuation">]</span><span class="token punctuation">)</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br></div></div>',41),t={render:function(n,a){return e}}}}]);